import React, { useState, useEffect } from 'react';
import api from '../services/api';

const CommentForm = ({ postId, type }) => {
  const [body, setBody] = useState('');
  const [comments, setComments] = useState([]);

  useEffect(() => {
    const fetchComments = async () => {
      const res = await api.get(`/comments?type=${type}&postId=${postId}`);
      setComments(res.data);
    };
    fetchComments();
  }, [postId, type]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await api.post('/comments', { body, type, postId }, {
        headers: { Authorization: `Bearer ${localStorage.getItem('token')}` }
      });
      setBody('');
      // Refresh comments
      const res = await api.get(`/comments?type=${type}&postId=${postId}`);
      setComments(res.data);
    } catch (err) {
      alert('Error');
    }
  };

  return (
    <div>
      <form onSubmit={handleSubmit}>
        <input type="text" value={body} onChange={(e) => setBody(e.target.value)} placeholder="Comment" />
        <button type="submit">Add</button>
      </form>
      <ul>
        {comments.map(c => <li key={c._id}>{c.body}</li>)}
      </ul>
    </div>
  );
};

export default CommentForm;
